INSERT INTO enrollment (student_id, section_id, status, enrolled_at) SELECT ci.student_id, ci.section_id, 'ENROLLED', SYSTIMESTAMP FROM cart_item ci JOIN course_section cs ON cs.section_id = ci.section_id WHERE ci.student_id = #{studentId}
AND ci.cart_id IN
#{cartItemId}
AND cs.enrolled_count < cs.capacity AND NOT EXISTS ( SELECT 1 FROM enrollment e WHERE e.student_id = ci.student_id AND e.section_id = ci.section_id AND e.status = 'ENROLLED' )

